  1	import { type MouseEvent as ReactMouseEvent, type Ref, useState } from 'react';
  2	
  3	import type { EnumGroup, EnumValue } from '@components/common/utils/types';
  4	import {
  5	  Badge,
  6	  MenuToggle,
  7	  type MenuToggleElement,
  8	  Select,
  9	  SelectGroup,
 10	  SelectList,
 11	  SelectOption,
 12	  ToolbarFilter,
 13	} from '@patternfly/react-core';
 14	import { FilterIcon } from '@patternfly/react-icons';
 15	import { isEmpty } from '@utils/helpers';
 16	
 17	import type { FilterTypeProps } from './types';
 18	
 19	const renderOptions = (
 20	  supportedGroups: EnumGroup[],
 21	  supportedEnumValues: EnumValue[],
 22	  selectedEnumIds: string[],
 23	) =>
 24	  supportedGroups.map(({ groupId, label }) => (
 25	    <SelectGroup key={groupId} label={label}>
 26	      <SelectList>
 27	        {supportedEnumValues
 28	          .filter((item) => item.groupId === groupId)
 29	          .map(({ id, label: itemLabel }) => (
 30	            <SelectOption
 31	              hasCheckbox
 32	              key={id}
 33	              value={itemLabel}
 34	              isSelected={selectedEnumIds.includes(id)}
 35	            >
 36	              {itemLabel}
 37	            </SelectOption>
 38	          ))}
 39	      </SelectList>
 40	    </SelectGroup>
 41	  ));
 42	
 43	/**
 44	 * This Filter type enables selecting one or many enum values that are separated by groups.
 45	 *
 46	 * **Enum contract:**<br>
 47	 * 1) values are grouped only for presentation and better user experience - logically it's one enum.<br>
 48	 * 2) enum IDs(not translated identifiers) are required to be constant and unique within the enum.<br>
 49	 * 3) the translated labels are not checked for duplication and simply displayed.<br>
 50	 * 4) groups are expected not to overlap (one item may belong to only one group).<br>
 51	 * 5) items not assigned to any of the supported groups are skipped.
 52	 *
 53	 *
 54	 * **FilterTypeProps are interpreted as follows:**<br>
 55	 * 1) selectedFilters - selected enum IDs.<br>
 56	 * 2) onFilterUpdate - accepts the list of selected enum IDs.<br>
 57	 * 3) supportedValues - supported enum values.<br>
 58	 * 4) supportedGroups - groups for supported enum values.
 59	 *
 60	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
 61	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/Filter/GroupedEnumFilter.tsx)
 62	 */
 63	export const GroupedEnumFilter = ({
 64	  hasMultipleResources,
 65	  onFilterUpdate: onSelectedEnumIdsChange,
 66	  placeholderLabel,
 67	  selectedFilters: selectedEnumIds = [],
 68	  showFilter = true,
 69	  showFilterIcon,
 70	  supportedGroups = [],
 71	  supportedValues: supportedEnumValues = [],
 72	}: FilterTypeProps) => {
 73	  const [isOpen, setIsOpen] = useState(false);
 74	
 75	  // simplify lookup
 76	  const id2enum = Object.fromEntries(
 77	    supportedEnumValues.map(({ id, ...rest }) => [id, { id, ...rest }]),
 78	  );
 79	
 80	  const label2enum = Object.fromEntries(
 81	    supportedEnumValues.map(({ label, ...rest }) => [label, { label, ...rest }]),
 82	  );
 83	
 84	  const deleteGroup = (groupId: string): void => {
 85	    if (hasMultipleResources) {
 86	      onSelectedEnumIdsChange([], groupId);
 87	      return;
 88	    }
 89	
 90	    onSelectedEnumIdsChange(
 91	      selectedEnumIds.filter((id) => id2enum[id] && id2enum[id].groupId !== groupId),
 92	    );
 93	  };
 94	
 95	  const deleteFilter = (id: string): void => {
 96	    if (hasMultipleResources) {
 97	      onSelectedEnumIdsChange(
 98	        selectedEnumIds.filter(
 99	          (selectedId) =>
100	            id2enum[selectedId]?.resourceFieldId === id2enum[id]?.resourceFieldId &&
101	            selectedId !== id,
102	        ),
103	        id2enum[id].resourceFieldId,
104	      );
105	    }
106	
107	    onSelectedEnumIdsChange(
108	      selectedEnumIds.filter((enumId) => id2enum[enumId] && id !== enumId),
109	      id2enum[id].resourceFieldId,
110	    );
111	  };
112	
113	  const hasFilter = (id: string): boolean =>
114	    Boolean(id2enum[id]) && Boolean(selectedEnumIds.find((enumId) => enumId === id));
115	
116	  const addFilter = (id: string): void => {
117	    if (hasMultipleResources) {
118	      onSelectedEnumIdsChange(
119	        [
120	          ...selectedEnumIds.filter(
121	            (selectedId) => id2enum[selectedId]?.resourceFieldId === id2enum[id]?.resourceFieldId,
122	          ),
123	          id,
124	        ],
125	        id2enum[id].resourceFieldId,
126	      );
127	    }
128	
129	    onSelectedEnumIdsChange(
130	      [...selectedEnumIds.filter((selectedId) => id2enum[selectedId]), id],
131	      id2enum[id].resourceFieldId,
132	    );
133	  };
134	
135	  const onSelect = (_event: ReactMouseEvent | undefined, value: string | number | undefined) => {
136	    const label = value?.toString();
137	    if (label) {
138	      const labelId = label2enum?.[label] ? label2enum[label]?.id : label;
139	      if (hasFilter(labelId)) {
140	        deleteFilter(labelId);
141	      } else {
142	        addFilter(labelId);
143	      }
144	    }
145	  };
146	
147	  const onToggleClick = () => {
148	    setIsOpen((prev) => !prev);
149	  };
150	
151	  const toggle = (toggleRef: Ref<MenuToggleElement>) => (
152	    <MenuToggle
153	      ref={toggleRef}
154	      onClick={onToggleClick}
155	      isExpanded={isOpen}
156	      isFullWidth
157	      {...(showFilterIcon && { icon: <FilterIcon /> })}
158	    >
159	      {placeholderLabel}
160	      {!isEmpty(selectedEnumIds) && (
161	        <Badge isRead className="pf-v6-u-ml-sm">
162	          {selectedEnumIds.length}
163	        </Badge>
164	      )}
165	    </MenuToggle>
166	  );
167	
168	  return (
169	    <>
170	      {/**
171	       * use nested ToolbarFilter trick borrowed from the Openshift Console filter-toolbar:
172	       * 1. one Select belongs to multiple ToolbarFilters.
173	       * 2. each ToolbarFilter provides a different chip category
174	       * 3. a chip category maps to group within the Select */}
175	      {supportedGroups.reduce(
176	        (acc, { groupId, label }) => (
177	          <ToolbarFilter
178	            labels={selectedEnumIds
179	              .filter((id) => id2enum[id])
180	              .map((id) => id2enum[id])
181	              .filter((enumVal) => enumVal.groupId === groupId)
182	              .map(({ id, label: enumLabel }) => ({ key: id, node: enumLabel }))}
183	            deleteLabel={(category, option) => {
184	              // values are one enum so id is enough to identify (category is not needed)
185	              const id = typeof option === 'string' ? option : option.key;
186	              deleteFilter(id);
187	            }}
188	            deleteLabelGroup={(category) => {
189	              const categoryId = typeof category === 'string' ? category : category.key;
190	              deleteGroup(categoryId);
191	            }}
192	            categoryName={{ key: groupId, name: label }}
193	            showToolbarItem={showFilter}
194	          >
195	            {acc}
196	          </ToolbarFilter>
197	        ),
198	        // This select is different from most and cannot use the common Select
199	        // eslint-disable-next-line no-restricted-syntax
200	        <Select
201	          role="menu"
202	          aria-label={placeholderLabel}
203	          isOpen={isOpen}
204	          selected={supportedEnumValues.filter(({ id }) => selectedEnumIds.includes(id))}
205	          onSelect={onSelect}
206	          onOpenChange={(nextOpen: boolean) => {
207	            setIsOpen(nextOpen);
208	          }}
209	          toggle={toggle}
210	          shouldFocusToggleOnSelect
211	          shouldFocusFirstItemOnOpen={false}
212	          popperProps={{
213	            appendTo: document.body,
214	            direction: 'down',
215	            enableFlip: true,
216	          }}
217	        >
218	          <SelectList>
219	            {renderOptions(supportedGroups, supportedEnumValues, selectedEnumIds)}
220	          </SelectList>
221	        </Select>,
222	      )}
223	    </>
224	  );
225	};

